create temporary table tmp_target_materials on commit drop as
select distinct
  m.id as material_id,
  m.source_url,
  m.price,
  m.name,
  m.supplier_name
from public.materials m
join public.room_objects ro on ro.selected_material_id = m.id
join public.rooms r on r.id = ro.room_id
join public.houses h on h.id = r.house_id
join public.projects p on p.id = h.project_id
where p.name = 'Srithanu - Imported'
  and m.source_url is not null
  and m.source_url <> '';

update public.materials m
set
  supplier_name = coalesce(nullif(f.fetched_supplier, ''), m.supplier_name),
  source_url = coalesce(nullif(f.final_url, ''), m.source_url),
  price = case
    when f.fetched_price is not null
      and f.fetched_price > 0
      and coalesce(m.price, 0) <= 1
    then f.fetched_price
    else m.price
  end
from tmp_target_materials tm
join tmp_fetched_links f on f.source_url = tm.source_url
where m.id = tm.material_id
  and (
    (nullif(f.fetched_supplier, '') is not null and m.supplier_name is distinct from f.fetched_supplier)
    or (nullif(f.final_url, '') is not null and m.source_url is distinct from f.final_url)
    or (
      f.fetched_price is not null
      and f.fetched_price > 0
      and coalesce(m.price, 0) <= 1
      and m.price is distinct from f.fetched_price
    )
  );

insert into public.material_images (material_id, image_url, sort_order)
select
  tm.material_id,
  f.fetched_image_url,
  coalesce((
    select max(mi.sort_order) + 1
    from public.material_images mi
    where mi.material_id = tm.material_id
  ), 0)
from tmp_target_materials tm
join tmp_fetched_links f on f.source_url = tm.source_url
where nullif(f.fetched_image_url, '') is not null
  and not exists (
    select 1
    from public.material_images mi
    where mi.material_id = tm.material_id
      and mi.image_url = f.fetched_image_url
  );

